async () => {
  // Global usage
  const globalLi = document.querySelector('.ciu-data li h4');
  const globalUsage = globalLi ? globalLi.nextElementSibling.textContent.split(' ')[0] : 'Not found';

  // Chrome earliest full support
  const chromeDiv = Array.from(document.querySelectorAll('.ciu-browser h4')).find(h => h.textContent.trim() === 'Chrome');
  let chromeVersion = 'Not found';
  if (chromeDiv) {
    const supports = chromeDiv.parentElement.querySelectorAll('.ciu-support');
    for (let support of supports) {
      if (support.textContent.includes('Supported')) {
        const versionText = support.previousElementSibling ? support.previousElementSibling.textContent : support.textContent.split(' ')[0];
        const version = versionText.split(' ')[0].split('-')[0]; // earliest in range
        if (!chromeVersion || parseInt(version) < parseInt(chromeVersion)) {
          chromeVersion = version;
        }
      }
    }
  }

  // Firefox earliest full support
  const firefoxDiv = Array.from(document.querySelectorAll('.ciu-browser h4')).find(h => h.textContent.trim() === 'Firefox');
  let firefoxVersion = 'Not found';
  if (firefoxDiv) {
    const supports = firefoxDiv.parentElement.querySelectorAll('.ciu-support');
    for (let support of supports) {
      if (support.textContent.includes('Supported')) {
        const versionText = support.previousElementSibling ? support.previousElementSibling.textContent : support.textContent.split(' ')[0];
        const version = versionText.split(' ')[0].split('-')[0];
        if (!firefoxVersion || parseInt(version) < parseInt(firefoxVersion)) {
          firefoxVersion = version;
        }
      }
    }
  }

  // Known Issues count
  const knownIssuesTab = Array.from(document.querySelectorAll('[role="tab"]')).find(tab => tab.textContent.includes('Known issues'));
  let knownIssuesCount = '0';
  if (knownIssuesTab) {
    const match = knownIssuesTab.textContent.match(/Known issues \((\d+)\)/);
    if (match) {
      knownIssuesCount = match[1];
    }
  }

  return { globalUsage, chromeVersion, firefoxVersion, knownIssuesCount };
}

